const googleMapsKey = (import.meta as any).env?.VITE_GOOGLE_MAPS_API_KEY || '';
declare global { interface Window { google?: any; __gmapsPromise?: Promise<void>; } }
function loadGoogleMaps(){
  if(!googleMapsKey) return Promise.reject(new Error('Nedostaje VITE_GOOGLE_MAPS_API_KEY'));
  if(window.google?.maps) return Promise.resolve();
  if(window.__gmapsPromise) return window.__gmapsPromise;
  window.__gmapsPromise = new Promise((resolve,reject)=>{
    const script=document.createElement('script');
    script.src=`https://maps.googleapis.com/maps/api/js?key=${encodeURIComponent(googleMapsKey)}&libraries=places`;
    script.async=true; script.defer=true; script.onload=()=>resolve(); script.onerror=()=>reject(new Error('Google Maps se nije učitao. Provjeri API key i billing.'));
    document.head.appendChild(script);
  });
  return window.__gmapsPromise;
}
async function api(path:string, opts:any={}){
  const token = localStorage.getItem(tokenKey);
  const res = await fetch('/api'+path, { ...opts, headers:{ 'Content-Type':'application/json', ...(token?{Authorization:'Bearer '+token}:{}), ...(opts.headers||{}) }});
  const data = await res.json().catch(()=>({})); if(!res.ok) throw new Error(data.error || 'API greška'); return data;
}

