function hav(a:[number,number],b:[number,number]){const R=6371, dLat=(b[0]-a[0])*Math.PI/180, dLon=(b[1]-a[1])*Math.PI/180; const x=Math.sin(dLat/2)**2+Math.cos(a[0]*Math.PI/180)*Math.cos(b[0]*Math.PI/180)*Math.sin(dLon/2)**2; return 2*R*Math.asin(Math.sqrt(x));}
function routeCalc(origin:string,destination:string,via:string,cons=30){ const pts=[origin, ...(via?via.split(',').map(s=>s.trim()).filter(Boolean):[]), destination].map(x=>cities[x]).filter(Boolean) as [number,number][]; let km=0; for(let i=1;i<pts.length;i++) km += hav(pts[i-1],pts[i])*1.22; const h=km/68; const rests=[]; for(let t=4.5;t<h;t+=5.25) rests.push({atHour:t, breakMin:t+0.75<h?45:0, rule:'EU 561/2006: nakon najviše 4h30 vožnje obvezna pauza 45 min'}); const near=stops.map(s=>({name:s[0] as string, kmFromRoute: pts[0]?Math.min(...pts.map(p=>hav(p,[s[1] as number,s[2] as number]))):999})).sort((a,b)=>a.kmFromRoute-b.kmFromRoute).slice(0,5); return {distance_km:+km.toFixed(1), duration_h:+h.toFixed(2), fuel_liters:+(km*cons/100).toFixed(1), toll_estimate:+(km*0.18).toFixed(2), rest_plan:rests, stops:near}; }
function MiniMap({origin,destination,via}:{origin:string;destination:string;via?:string}){ const names=[origin,...(via?via.split(',').map(x=>x.trim()).filter(Boolean):[]),destination].filter(x=>cities[x]); const pts=names.map(n=>cities[n]); if(pts.length<2) return <div className="mapEmpty">Unesite gradove iz liste: {Object.keys(cities).slice(0,12).join(', ')}...</div>; const lats=pts.map(p=>p[0]), lons=pts.map(p=>p[1]); const minLat=Math.min(...lats), maxLat=Math.max(...lats), minLon=Math.min(...lons), maxLon=Math.max(...lons); const xy=(p:[number,number])=>[40+((p[1]-minLon)/(maxLon-minLon||1))*520,260-(40+((p[0]-minLat)/(maxLat-minLat||1))*180)]; const line=pts.map(p=>xy(p).join(',')).join(' '); return <svg className="map" viewBox="0 0 600 300"><defs><linearGradient id="g" x1="0" x2="1"><stop stopColor="#0ea5e9"/><stop offset="1" stopColor="#22c55e"/></linearGradient></defs><rect width="600" height="300" rx="20" fill="var(--map)"/><polyline points={line} fill="none" stroke="url(#g)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round"/>{pts.map((p,i)=>{const [x,y]=xy(p);return <g key={i}><circle cx={x} cy={y} r="9" fill={i===0?'#22c55e':i===pts.length-1?'#ef4444':'#f59e0b'}/><text x={x+12} y={y-10} fill="currentColor" fontSize="13">{names[i]}</text></g>})}</svg> }

function GoogleRouteMap({origin,destination,via,cons,onCalc}:{origin:string;destination:string;via?:string;cons:number;onCalc:(r:any)=>void}){
 const divRef = React.useRef<HTMLDivElement|null>(null); const [err,setErr]=useState('');
 useEffect(()=>{ let alive=true; if(!googleMapsKey){setErr('Google Maps API key nije postavljen. Koristi se fallback karta.'); return;} loadGoogleMaps().then(()=>{ if(!alive||!divRef.current) return; const google=window.google; const map=new google.maps.Map(divRef.current,{center:{lat:45.815,lng:15.982},zoom:6,mapTypeControl:false,streetViewControl:false,fullscreenControl:true}); const renderer=new google.maps.DirectionsRenderer({map,suppressMarkers:false,polylineOptions:{strokeColor:'#0ea5e9',strokeWeight:6}}); const service=new google.maps.DirectionsService(); const waypoints=(via||'').split(',').map(x=>x.trim()).filter(Boolean).map(location=>({location,stopover:false})); service.route({origin,destination,waypoints,travelMode:google.maps.TravelMode.DRIVING,drivingOptions:{departureTime:new Date(),trafficModel:google.maps.TrafficModel.BEST_GUESS},provideRouteAlternatives:false},(result:any,status:string)=>{ if(!alive) return; if(status!=='OK'||!result){setErr('Google Directions greška: '+status); return;} renderer.setDirections(result); const route=result.routes[0]; const legs=route.legs||[]; const meters=legs.reduce((sum:number,l:any)=>sum+(l.distance?.value||0),0); const seconds=legs.reduce((sum:number,l:any)=>sum+(l.duration_in_traffic?.value||l.duration?.value||0),0); const km=meters/1000; const h=seconds/3600; const rest_plan=[]; for(let t=4.5;t<h;t+=5.25) rest_plan.push({atHour:+t.toFixed(2),breakMin:t+0.75<h?45:0,rule:'EU 561/2006: nakon najviše 4h30 vožnje obvezna pauza 45 min'}); const near=stops.map(st=>({name:st[0] as string, kmFromRoute:0})).slice(0,5); onCalc({distance_km:+km.toFixed(1),duration_h:+h.toFixed(2),fuel_liters:+(km*Number(cons||30)/100).toFixed(1),toll_estimate:+(km*0.18).toFixed(2),rest_plan,stops:near,source:'google'}); }); }).catch((e:any)=>setErr(e.message)); return()=>{alive=false}; },[origin,destination,via,cons]);
 return <><div ref={divRef} className="googleMap"></div>{err&&<div className="mapNotice">{err}</div>}</>
}
