function GPSFleetMap({rows,refs}:{rows:Row[];refs:Record<string,Row[]>}){
 const divRef=React.useRef<HTMLDivElement|null>(null); const mapRef=React.useRef<any>(null); const markersRef=React.useRef<any[]>([]); const [err,setErr]=useState(''); const [query,setQuery]=useState(''); const [selected,setSelected]=useState<Row|null>(null);
 const filtered=rows.filter(r=>nameOf('trucks',r.truck_id,refs).toLowerCase().includes(query.toLowerCase()) || nameOf('drivers',r.driver_id,refs).toLowerCase().includes(query.toLowerCase()) || String(r.note||'').toLowerCase().includes(query.toLowerCase()));
 useEffect(()=>{ if(!filtered.length) return; if(!googleMapsKey){setErr('Za custom live GPS kartu postavite VITE_GOOGLE_MAPS_API_KEY.'); return;} loadGoogleMaps().then(()=>{ if(!divRef.current) return; const google=window.google; const first=filtered.find(r=>r.lat&&r.lng)||filtered[0]; if(!mapRef.current){ mapRef.current=new google.maps.Map(divRef.current,{center:{lat:Number(first.lat||45.815),lng:Number(first.lng||15.982)},zoom:7,mapTypeControl:false,streetViewControl:false,fullscreenControl:false,zoomControl:true,styles:[{featureType:'poi',stylers:[{visibility:'off'}]},{featureType:'transit',stylers:[{visibility:'off'}]},{featureType:'road',elementType:'geometry',stylers:[{color:'#e5eef8'}]},{featureType:'water',stylers:[{color:'#bfdbfe'}]}]}); }
 markersRef.current.forEach(m=>m.setMap(null)); markersRef.current=[]; const bounds=new google.maps.LatLngBounds(); filtered.filter(r=>r.lat&&r.lng).forEach(r=>{ const pos={lat:Number(r.lat),lng:Number(r.lng)}; bounds.extend(pos); const status=Number(r.speed_kmh||0)>3?'#16a34a':'#f59e0b'; const marker=new google.maps.Marker({map:mapRef.current,position:pos,title:`${nameOf('trucks',r.truck_id,refs)} · ${r.speed_kmh||0} km/h`,icon:{url:truckMarkerSvg(status),scaledSize:new google.maps.Size(46,46)}}); marker.addListener('click',()=>setSelected(r)); markersRef.current.push(marker); }); if(filtered.length>1) mapRef.current.fitBounds(bounds); else mapRef.current.setCenter({lat:Number(first.lat||45.815),lng:Number(first.lng||15.982)}); }).catch((e:any)=>setErr(e.message)); },[filtered.length,query,refs]);
 return <div className="fleetConsole"><aside className="fleetPanel"><div className="fleetHead"><Icon name="gps"/><div><h3>Live flota</h3><p>Custom GPS kontrolni centar</p></div></div><input className="fleetSearch" placeholder="Traži kamion, vozača ili napomenu" value={query} onChange={e=>setQuery(e.target.value)}/><div className="fleetList">{filtered.map(r=><button key={r.id} className={selected?.id===r.id?'active':''} onClick={()=>setSelected(r)}><b>{nameOf('trucks',r.truck_id,refs)}</b><span>{nameOf('drivers',r.driver_id,refs)} · {r.speed_kmh||0} km/h</span><small>{Number(r.lat).toFixed?.(4)}, {Number(r.lng).toFixed?.(4)}</small></button>)}</div></aside><section className="fleetMapWrap"><div ref={divRef} className="googleMap fleetPro"></div>{err&&<div className="mapNotice">{err}</div>}{!rows.length&&<p className="muted emptyFleet">Nema GPS pozicija. Dodajte vozilo s lat/lng koordinatama.</p>}{selected&&<div className="vehicleCard"><div><b>{nameOf('trucks',selected.truck_id,refs)}</b><span>{nameOf('drivers',selected.driver_id,refs)}</span></div><div className="vehicleStats"><span>{selected.speed_kmh||0} km/h</span><span>{selected.ignition?'Kontakt ON':'Kontakt OFF'}</span><span>{date(selected.position_time)}</span></div><p>{selected.note||'Nema napomene.'}</p></div>}</section></div>
}

function nameOf(ref:string|undefined,id:any,refs:Record<string,Row[]>){ if(!ref||!id) return '—'; const r=refs[ref]?.find(x=>x.id===id); return r?.name || r?.plate || r?.order_no || r?.invoice_no || r?.offer_no || id?.slice?.(0,8) || '—'; }


