function App(){
 const [token,setToken]=useState(localStorage.getItem(tokenKey)); const [user,setUser]=useState<any>(null); const [company,setCompany]=useState<any>(null); const [view,setView]=useState('dashboard'); const [theme,setTheme]=useState(localStorage.getItem('theme')||'light'); const [toast,setToast]=useState('');
 useEffect(()=>{document.documentElement.dataset.theme=theme; localStorage.setItem('theme',theme)},[theme]);
 useEffect(()=>{ if(token) api('/me').then(d=>{setUser(d.user);setCompany(d.company)}).catch(()=>logout()); },[token]);
 function logout(){localStorage.removeItem(tokenKey);setToken(null);setUser(null);}
 if(!token) return <Auth onLogin={(t:string,u:any,c:any)=>{localStorage.setItem(tokenKey,t);setToken(t);setUser(u);setCompany(c)}} setToast={setToast} toast={toast}/>;
 const mod=modules.find(m=>m.key===view);
 return <div className="shell"><aside><div className="brand"><b>AdriaTMS</b><span>ERP za prijevoznike</span></div><button className={view==='dashboard'?'sel':''} onClick={()=>setView('dashboard')}><Icon name="dashboard"/> <span>Dashboard</span></button>{modules.map(m=><button key={m.key} className={view===m.key?'sel':''} onClick={()=>setView(m.key)}><Icon name={m.icon}/> <span>{m.label}</span></button>)}{specialViews.map(v=><button key={v.key} className={view===v.key?'sel':''} onClick={()=>setView(v.key)}><Icon name={v.icon}/> <span>{v.label}</span></button>)}<div className="muted block">Svi moduli iz specifikacije su aktivni: Dashboard, flota, GPS, tahograf, financije, PDF/Excel, analitika, backup, postavke, administracija i 150 poslovnih funkcija.</div></aside><main><header><div><h1>{mod?mod.label:'Dashboard'}</h1><p>{mod?mod.desc:'Pregled flote, prihoda, troškova i rokova.'}</p></div><div className="headerActions"><span className="pill">{company?.name}</span><button onClick={()=>setTheme(theme==='dark'?'light':'dark')}>{theme==='dark'?'☀️':'🌙'}</button><button onClick={logout}>Odjava</button></div></header>{toast&&<div className="toast" onClick={()=>setToast('')}>{toast}</div>}{view==='dashboard'?<Dashboard setView={setView}/>:view==='analytics'?<Analytics/>:view==='backup'?<Backup setToast={setToast}/>:view==='admin'?<Admin setToast={setToast}/>:view==='pdf'?<PdfCenter/>:view==='excel'?<ExcelCenter/>:view==='features150'?<Features150 setToast={setToast}/>:mod?<ModuleView module={mod} setToast={setToast}/>:<Dashboard setView={setView}/>}</main></div>
}
function Auth({onLogin,setToast,toast}:any){ const [mode,setMode]=useState<'login'|'register'>('login'); const [f,setF]=useState<any>({country:'HR'}); const [busy,setBusy]=useState(false); async function submit(e:any){ e.preventDefault(); setBusy(true); try{ const d= await api('/auth/'+mode,{method:'POST',body:JSON.stringify(f)}); onLogin(d.token,d.user,d.company);}catch(e:any){setToast(e.message)} finally{setBusy(false)} } async function setup(){ try{setBusy(true); await api('/setup',{method:'POST'}); setToast('Baza je inicijalizirana. Sada se možete registrirati.')}catch(e:any){setToast(e.message)}finally{setBusy(false)} }
 return <div className="auth"><div className="authCard"><h1>AdriaTMS ERP</h1><p>Standalone Netlify + Neon aplikacija za transport, flotu, fakture i operativu.</p>{toast&&<div className="toast">{toast}</div>}<div className="tabs"><button className={mode==='login'?'sel':''} onClick={()=>setMode('login')}>Prijava</button><button className={mode==='register'?'sel':''} onClick={()=>setMode('register')}>Registracija tvrtke</button></div><form onSubmit={submit}>{mode==='register'&&<><input required placeholder="Naziv tvrtke" onChange={e=>setF({...f,companyName:e.target.value})}/><input required placeholder="OIB tvrtke" onChange={e=>setF({...f,oib:e.target.value})}/><input required placeholder="Vaše ime" onChange={e=>setF({...f,name:e.target.value})}/><input placeholder="Adresa" onChange={e=>setF({...f,address:e.target.value})}/><input placeholder="Grad" onChange={e=>setF({...f,city:e.target.value})}/></>} {mode==='login'||mode==='register'?<><input required type="email" placeholder="Email" onChange={e=>setF({...f,email:e.target.value})}/><input required type="password" placeholder="Lozinka" onChange={e=>setF({...f,password:e.target.value})}/></>:null}<button disabled={busy}>{busy?'Radim...':mode==='login'?'Prijavi se':'Registriraj tvrtku'}</button></form><button className="ghost" onClick={setup}>Prvi put? Inicijaliziraj Neon bazu</button><small>Sigurnost: lozinke se spremaju kao bcrypt hash, sesija je JWT, podaci su odvojeni po company_id.</small></div></div> }
function Dashboard({setView}:any){ const [d,setD]=useState<any>(null); useEffect(()=>{api('/dashboard').then(setD)},[]); if(!d) return <div className="grid"><div className="card">Učitavanje...</div></div>; const revenue=(d.transports||[]).reduce((s:any,x:any)=>s+Number(x.total||0),0); const invTotal=(d.invoices||[]).reduce((s:any,x:any)=>s+Number(x.total||0),0); return <><div className="kpis"><K label="Kamioni" val={d.trucks}/><K label="Vozači" val={d.drivers}/><K label="Prihod prijevoza" val={money(revenue)}/><K label="Fakturirano" val={money(invTotal)}/><K label="Gorivo mj." val={money(d.monthlyFuel.total)}/><K label="Troškovi mj." val={money(d.monthlyExpenses+d.monthlyService)}/></div><div className="grid two"><div className="card"><h3>Status prijevoza</h3>{(d.transports||[]).map((x:any)=><div className="row" key={x.status}><b>{x.status}</b><span>{x.n} · {money(x.total)}</span></div>)}<button onClick={()=>setView('transports')}>Otvori dispečing</button></div><div className="card"><h3>Upozorenja rokova</h3>{d.alerts?.length?d.alerts.map((a:any,i:number)=><div className="alert" key={i}>{a.type}: <b>{a.label}</b> do {date(a.due)}</div>):<p className="muted">Nema rokova u sljedećih 30 dana.</p>}</div></div><div className="card"><h3>Što je implementirano</h3><p>CRUD, validacije, role-permissions, audit log, izračun ruta/goriva/pauza, offline karta, preporuke odmorišta, putni nalog, fakture/ponude s ispisom u PDF kroz browser print, CSV/Excel izvoz, dashboard i responsive dark/light UI.</p></div></> }
function K({label,val}:any){return <div className="kpi"><span>{label}</span><b>{val}</b></div>}
function ModuleView({module,setToast}:{module:Module;setToast:(s:string)=>void}){ const [rows,setRows]=useState<Row[]>([]), [refs,setRefs]=useState<Record<string,Row[]>>({}), [edit,setEdit]=useState<Row|null>(null), [search,setSearch]=useState(''); const [route,setRoute]=useState<any>(null); const refNames=Array.from(new Set(module.fields.map(f=>f.ref).filter(Boolean))) as string[]; async function load(){ const [r,...rr]=await Promise.all([api('/'+module.key+'?search='+encodeURIComponent(search)),...refNames.map(x=>api('/'+x))]); setRows(r); const obj:any={}; refNames.forEach((n,i)=>obj[n]=rr[i]); setRefs(obj); }
 useEffect(()=>{load().catch(e=>setToast(e.message))},[module.key]); async function save(data:Row){ try{ if(module.key==='invoices'){data.vat_amount=+(Number(data.subtotal||0)*Number(data.vat_rate||25)/100).toFixed(2); data.total=+(Number(data.subtotal||0)+data.vat_amount).toFixed(2)} if(module.key==='routes'){data.rest_plan=route?.rest_plan||data.rest_plan}
      if(module.key==='app_settings' && typeof data.setting_value==='string'){try{data.setting_value=JSON.parse(data.setting_value)}catch{throw new Error('Postavka mora biti valjani JSON, npr. {"pdv":25}')}} await api('/'+module.key+(data.id?'/'+data.id:''),{method:data.id?'PUT':'POST',body:JSON.stringify(data)}); setEdit(null); await load(); setToast('Spremljeno.')}catch(e:any){setToast(e.message)} }
 async function del(id:string){ if(confirm('Obrisati zapis?')) try{await api('/'+module.key+'/'+id,{method:'DELETE'}); await load(); setToast('Obrisano.')}catch(e:any){setToast(e.message)} }
 async function next(){ const kind=module.key==='invoices'?'invoice':module.key==='offers'?'offer':'transport'; const n=await api('/next-number/'+kind); setEdit({...(edit||{}), [module.key==='invoices'?'invoice_no':module.key==='offers'?'offer_no':'order_no']:n.number}); }
 function exportCsv(){ const csv=[Object.keys(rows[0]||{}).join(';'),...rows.map(r=>Object.values(r).map(v=>'"'+String(v??'').replace(/"/g,'""')+'"').join(';'))].join('\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'})); a.download=module.key+'.csv'; a.click(); }
 return <><div className="toolbar"><input placeholder="Pretraži..." value={search} onChange={e=>setSearch(e.target.value)} onKeyDown={e=>{if(e.key==='Enter')load()}}/><button onClick={load}>Traži</button><button onClick={()=>setEdit({})}>+ Novi zapis</button>{['transports','invoices','offers'].includes(module.key)&&<button onClick={next}>Sljedeći broj</button>}<button onClick={exportCsv}>Excel/CSV</button></div>{module.key==='routes'&&<RoutePanel onCalc={setRoute}/>} {module.key==='gps_positions'&&<GPSFleetMap rows={rows} refs={refs}/>}<div className="card tableWrap"><table><thead><tr>{module.fields.slice(0,7).map(f=><th key={f.key}>{f.label}</th>)}<th>Akcije</th></tr></thead><tbody>{rows.map(r=><tr key={r.id}>{module.fields.slice(0,7).map(f=><td key={f.key}>{f.ref?nameOf(f.ref,r[f.key],refs):f.type==='checkbox'?(r[f.key]?'Da':'Ne'):String(r[f.key]??'—')}</td>)}<td><button onClick={()=>setEdit(r)}>Uredi</button>{module.print&&<button onClick={()=>printDoc(module.print!,r,refs)}>PDF</button>}<button className="danger" onClick={()=>del(r.id)}>Briši</button></td></tr>)}</tbody></table>{!rows.length&&<p className="muted center">Nema zapisa.</p>}</div>{edit&&<Form module={module} row={edit} refs={refs} route={route} onClose={()=>setEdit(null)} onSave={save}/>}</> }

type AddressValue = { street:string; number:string; postal:string; city:string; country:string; place?:string };
function fullAddress(a:AddressValue){ return [a.street && `${a.street} ${a.number||''}`.trim(), [a.postal,a.city].filter(Boolean).join(' '), a.country].filter(Boolean).join(', '); }
function AddressBox({title,value,onChange,accent}:{title:string;value:AddressValue;onChange:(v:AddressValue)=>void;accent:string}){
 const [suggestions,setSuggestions]=useState<any[]>([]); const [open,setOpen]=useState(false); const q=fullAddress(value);
 useEffect(()=>{ let alive=true; if(!googleMapsKey || q.length<5){setSuggestions([]); return;} const t=setTimeout(()=>{loadGoogleMaps().then(()=>{const svc=new window.google.maps.places.AutocompleteService(); svc.getPlacePredictions({input:q,componentRestrictions:{country:['hr','si','at','de','it','hu','ba','rs']},types:['address']},(preds:any[])=>{if(alive) setSuggestions(preds||[]);});}).catch(()=>{});},350); return()=>{alive=false;clearTimeout(t)}; },[q]);
 function pick(s:any){ const txt=s.description||''; const parts=txt.split(',').map((x:string)=>x.trim()); onChange({...value, place:txt, street:parts[0]||value.street, city:parts[1]||value.city}); setOpen(false); }
 return <div className="addressBox" style={{'--addr':accent} as any}><div className="addrTitle"><span></span><b>{title}</b></div><div className="addressGrid"><input placeholder="Ulica" value={value.street} onFocus={()=>setOpen(true)} onChange={e=>{onChange({...value,street:e.target.value,place:''});setOpen(true)}}/><input placeholder="Broj" value={value.number} onChange={e=>onChange({...value,number:e.target.value,place:''})}/><input placeholder="Poštanski broj" value={value.postal} onChange={e=>onChange({...value,postal:e.target.value,place:''})}/><input placeholder="Grad" value={value.city} onFocus={()=>setOpen(true)} onChange={e=>{onChange({...value,city:e.target.value,place:''});setOpen(true)}}/><input placeholder="Država" value={value.country} onChange={e=>onChange({...value,country:e.target.value,place:''})}/></div><div className="addrPreview">{value.place || fullAddress(value) || 'Unesite točnu adresu'}</div>{open&&suggestions.length>0&&<div className="suggestions">{suggestions.slice(0,5).map((x:any)=><button type="button" key={x.place_id} onClick={()=>pick(x)}><Icon name="gps"/><span>{x.description}</span></button>)}</div>}</div>
}
function RoutePanel({onCalc}:any){
 const [origin,setOrigin]=useState<AddressValue>({street:'',number:'',postal:'',city:'Zagreb',country:'Hrvatska'});
 const [destination,setDestination]=useState<AddressValue>({street:'',number:'',postal:'',city:'Split',country:'Hrvatska'});
 const [via,setVia]=useState(''); const [cons,setCons]=useState(30);
 const originText=origin.place || fullAddress(origin); const destinationText=destination.place || fullAddress(destination);
 const fallback=useMemo(()=>routeCalc(origin.city||originText,destination.city||destinationText,via,Number(cons||30)),[originText,destinationText,via,cons]);
 const [calc,setCalc]=useState<any>({...fallback,originText,destinationText,viaText:via});
 useEffect(()=>{ if(!googleMapsKey) setCalc({...fallback,originText,destinationText,viaText:via}); },[fallback.distance_km,fallback.duration_h,fallback.fuel_liters,originText,destinationText,via]);
 useEffect(()=>onCalc(calc),[calc.distance_km,calc.duration_h,calc.fuel_liters,calc.originText,calc.destinationText]);
 return <div className="mapExperience"><section className="mapControl"><div className="mapControlHead"><Icon name="routes"/><div><h3>Planiranje rute</h3><p>Točne adrese, prijedlozi i live izračun puta.</p></div></div><AddressBox title="Polazište" value={origin} onChange={setOrigin} accent="#16a34a"/><AddressBox title="Odredište" value={destination} onChange={setDestination} accent="#ef4444"/><label className="controlLabel">Međustajališta / via adrese<input placeholder="Npr. Ljubljana, Graz" value={via} onChange={e=>setVia(e.target.value)}/></label><label className="controlLabel">Potrošnja vozila l/100km<input type="number" value={cons} onChange={e=>setCons(Number(e.target.value||30))}/></label><div className="routeStats"><K label="Udaljenost" val={`${calc.distance_km||0} km`}/><K label="Trajanje" val={`${calc.duration_h||0} h`}/><K label="Gorivo" val={`${calc.fuel_liters||0} L`}/><K label="Cestarina" val={money(calc.toll_estimate)}/></div><div className="routeSection"><h4>Zakonske pauze</h4>{calc.rest_plan?.length?calc.rest_plan.map((x:any,i:number)=><div className="ruleItem" key={i}><b>{x.atHour}h</b><span>Pauza {x.breakMin} min · EU/RH 561/2006</span></div>):<p className="muted">Ruta je dovoljno kratka da nema obvezne pauze.</p>}</div><div className="routeSection"><h4>Predložena odmorišta</h4>{(calc.stops||[]).map((s:any)=><span className="pill" key={s.name}>{s.name}</span>)}</div></section><section className="mapCanvasPro">{googleMapsKey?<GoogleRouteMap origin={originText} destination={destinationText} via={via} cons={Number(cons||30)} onCalc={(r:any)=>setCalc({...r,originText,destinationText,viaText:via})}/>:<MiniMap origin={origin.city||'Zagreb'} destination={destination.city||'Split'} via={via}/>}<div className="mapFloating"><b>{calc.source==='google'?'Google Directions ruta':'Fallback ruta'}</b><span>{originText} → {destinationText}</span></div></section></div>
}
function Form({module,row,refs,route,onClose,onSave}:any){ const [f,setF]=useState<Row>(row); useEffect(()=>{ if(module.key==='routes'&&route) setF((x:Row)=>({...x, origin:x.origin||route.originText, destination:x.destination||route.destinationText, via:x.via||route.viaText, distance_km:route.distance_km,duration_h:route.duration_h,fuel_liters:route.fuel_liters,toll_estimate:route.toll_estimate,rest_plan:route.rest_plan})); },[route]); return <div className="modal"><form className="modalCard" onSubmit={e=>{e.preventDefault();onSave(f)}}><div className="modalHead"><h2>{row.id?'Uredi':'Novi'} · {module.label}</h2><button type="button" onClick={onClose}>✕</button></div><div className="formGrid">{module.fields.map((field:Field)=><label key={field.key}>{field.label}{field.ref?<select value={f[field.key]||''} onChange={e=>setF({...f,[field.key]:e.target.value||null})}><option value="">—</option>{refs[field.ref]?.map((r:Row)=><option key={r.id} value={r.id}>{r.name||r.plate||r.order_no||r.invoice_no}</option>)}</select>:field.type==='textarea'?<textarea required={field.required} value={f[field.key]||''} onChange={e=>setF({...f,[field.key]:e.target.value})}/>:field.type==='select'?<select required={field.required} value={f[field.key]||''} onChange={e=>setF({...f,[field.key]:e.target.value})}><option value="">—</option>{field.options?.map(o=><option key={o}>{o}</option>)}</select>:field.type==='checkbox'?<input type="checkbox" checked={!!f[field.key]} onChange={e=>setF({...f,[field.key]:e.target.checked})}/>:<input required={field.required} type={field.type||'text'} step={field.step||'0.01'} value={f[field.key]??''} onChange={e=>setF({...f,[field.key]:e.target.value})}/>}</label>)}</div><div className="modalActions"><button type="button" onClick={onClose}>Odustani</button><button>Spremi</button></div></form></div> }
function printDoc(kind:string,r:Row,refs:Record<string,Row[]>){ const customer=nameOf('customers',r.customer_id,refs), transport=nameOf('transports',r.transport_id,refs), truck=nameOf('trucks',r.truck_id,refs), driver=nameOf('drivers',r.driver_id,refs); let title=kind==='invoice'?'RAČUN':kind==='offer'?'PONUDA':'PUTNI NALOG'; let html=`<html><head><title>${title}</title><style>body{font-family:Arial;padding:36px;color:#111}h1{color:#0f766e}table{width:100%;border-collapse:collapse;margin-top:20px}td,th{border:1px solid #ddd;padding:10px}.right{text-align:right}.muted{color:#666}</style></head><body><h1>${title}</h1><p class="muted">Generirano iz AdriaTMS ERP</p>`; if(kind==='invoice') html+=`<h2>${r.invoice_no}</h2><p>Kupac: <b>${customer}</b></p><p>Datum: ${date(r.issue_date)} · Dospijeće: ${date(r.due_date)}</p><table><tr><th>Opis</th><th class="right">Osnovica</th><th>PDV</th><th class="right">Ukupno</th></tr><tr><td>Prijevoz ${transport}</td><td class="right">${money(r.subtotal)}</td><td>${r.vat_rate}% (${money(r.vat_amount)})</td><td class="right"><b>${money(r.total)}</b></td></tr></table><p>${r.notes||''}</p>`; else if(kind==='transport') html+=`<h2>${r.order_no}</h2><table><tr><td>Kupac</td><td>${customer}</td></tr><tr><td>Vozilo</td><td>${truck}</td></tr><tr><td>Vozač</td><td>${driver}</td></tr><tr><td>Utovar</td><td>${r.loading_place} · ${date(r.load_date)}</td></tr><tr><td>Istovar</td><td>${r.unloading_place} · ${date(r.unload_date)}</td></tr><tr><td>Teret</td><td>${r.cargo_desc} (${r.cargo_weight_kg||0} kg)</td></tr></table><p>Potpis disponenta: ____________________ Potpis vozača: ____________________</p>`; else html+=`<h2>${r.offer_no}</h2><p>Kupac: ${customer}</p><p>Vrijedi do: ${date(r.valid_until)}</p><table><tr><th>Opis</th><th class="right">Cijena</th></tr><tr><td>${r.route_desc||'Usluga prijevoza'}</td><td class="right">${money(r.price)}</td></tr></table>`; html+='</body></html>'; const w=window.open('','_blank'); if(w){w.document.write(html);w.document.close();w.print();} }

function Analytics(){
 const [d,setD]=useState<any>(null); useEffect(()=>{api('/analytics').then(setD)},[]); if(!d) return <div className="card">Učitavanje analitike...</div>;
 const chart=(rows:any[], key:string, label:string)=><div className="card"><h3>{label}</h3>{rows?.length?rows.map((r:any,i:number)=><div className="bar" key={i}><span>{r.m?date(r.m):(r.plate||r.name||r.status||('Modul '+r.module_id))}</span><b>{money(r[key]||r.total||r.amount||0)}</b></div>):<p className="muted">Nema podataka.</p>}</div>;
 return <div className="grid two">{chart(d.monthlyRevenue,'revenue','Prihod po mjesecima')}{chart(d.monthlyExpenses,'expenses','Troškovi po mjesecima')}{chart(d.fuelByTruck,'total','Gorivo po kamionu')}{chart(d.driverPerformance,'revenue','Učinak vozača')}{chart(d.invoiceStatus,'total','Status faktura')}{chart(d.featureReports,'amount','Izvještaji 150 funkcija')}</div>
}
function Backup({setToast}:any){ const [data,setData]=useState<any>(null); async function run(){try{const d=await api('/backup',{method:'POST'}); setData(d); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([JSON.stringify(d,null,2)],{type:'application/json'})); a.download='adriatms-backup.json'; a.click(); setToast('Backup kreiran i preuzet.')}catch(e:any){setToast(e.message)}} return <div className="card"><h3>Backup / export</h3><p>Izvoz svih podataka tvrtke iz Neon baze u JSON datoteku.</p><button onClick={run}>Kreiraj backup sada</button>{data&&<pre className="code">{JSON.stringify({exportedAt:data.exportedAt, tables:Object.fromEntries(Object.entries(data.tables).map(([k,v]:any)=>[k,v.length]))},null,2)}</pre>}</div> }
function Admin({setToast}:any){ const [rows,setRows]=useState<Row[]>([]),[edit,setEdit]=useState<Row|null>(null); async function load(){setRows(await api('/admin/users'))} useEffect(()=>{load().catch((e:any)=>setToast(e.message))},[]); async function save(u:Row){try{await api('/admin/users'+(u.id?'/'+u.id:''),{method:u.id?'PUT':'POST',body:JSON.stringify(u)});setEdit(null);await load();setToast('Korisnik spremljen.')}catch(e:any){setToast(e.message)}} return <><div className="toolbar"><button onClick={()=>setEdit({role:'viewer',active:true})}>+ Novi korisnik</button></div><div className="card tableWrap"><table><thead><tr><th>Ime</th><th>Email</th><th>Rola</th><th>Aktivan</th><th>Akcije</th></tr></thead><tbody>{rows.map(r=><tr key={r.id}><td>{r.name}</td><td>{r.email}</td><td>{r.role}</td><td>{r.active?'Da':'Ne'}</td><td><button onClick={()=>setEdit(r)}>Uredi</button></td></tr>)}</tbody></table></div>{edit&&<SimpleUserForm row={edit} onClose={()=>setEdit(null)} onSave={save}/>}</> }
function SimpleUserForm({row,onClose,onSave}:any){ const [f,setF]=useState<Row>(row); return <div className="modal"><form className="modalCard" onSubmit={e=>{e.preventDefault();onSave(f)}}><div className="modalHead"><h2>Korisnik</h2><button type="button" onClick={onClose}>✕</button></div><div className="formGrid"><label>Ime<input required value={f.name||''} onChange={e=>setF({...f,name:e.target.value})}/></label><label>Email<input required type="email" value={f.email||''} onChange={e=>setF({...f,email:e.target.value})}/></label><label>Rola<select value={f.role||'viewer'} onChange={e=>setF({...f,role:e.target.value})}>{['admin','dispatcher','accountant','driver','viewer'].map(x=><option key={x}>{x}</option>)}</select></label><label>Nova lozinka<input type="password" onChange={e=>setF({...f,password:e.target.value})}/></label><label>Aktivan<input type="checkbox" checked={f.active!==false} onChange={e=>setF({...f,active:e.target.checked})}/></label></div><div className="modalActions"><button type="button" onClick={onClose}>Odustani</button><button>Spremi</button></div></form></div> }
function PdfCenter(){ return <div className="card"><h3>PDF centar</h3><p>PDF se generira kroz browser print mehanizam. Otvorite Fakture, Ponude, Putne naloge ili CMR i kliknite PDF/Ispis.</p><ul><li>Račun kupcu s PDV obračunom</li><li>Ponuda kupcu</li><li>Putni nalog vozaču</li><li>CMR / transportni dokument</li></ul><button onClick={()=>window.print()}>Ispiši trenutni ekran</button></div> }
function ExcelCenter(){ return <div className="card"><h3>Excel centar</h3><p>Svaki modul ima CSV/Excel gumb. Izvoz je lokalni CSV kompatibilan s Excelom.</p><p>Podržano za flotu, vozače, kupce, prijevoze, fakture, gorivo, servise, GPS, tahograf, plaće, CMR i 150 poslovnih funkcija.</p></div> }
function Features150({setToast}:any){ const [mods,setMods]=useState<Row[]>([]),[mid,setMid]=useState(1),[rows,setRows]=useState<Row[]>([]),[edit,setEdit]=useState<Row|null>(null); useEffect(()=>{api('/feature-modules').then(setMods)},[]); async function load(id=mid){setRows(await api('/feature-records/'+id))} useEffect(()=>{load().catch((e:any)=>setToast(e.message))},[mid]); const mod=mods.find(m=>m.id===mid); async function save(r:Row){try{const payload={title:r.title,status:r.status,priority:r.priority,amount:r.amount,due_date:r.due_date,data:{opis:r.opis,odgovorna_osoba:r.odgovorna_osoba,rizik:r.rizik,napomena:r.napomena}}; await api('/feature-records/'+(r.id?r.id:mid),{method:r.id?'PUT':'POST',body:JSON.stringify(payload)});setEdit(null);await load();setToast('Funkcijski zapis spremljen.')}catch(e:any){setToast(e.message)}} async function del(id:string){if(confirm('Obrisati zapis?')){await api('/feature-records/'+id,{method:'DELETE'});await load();}}
 return <><div className="toolbar"><select value={mid} onChange={e=>setMid(Number(e.target.value))}>{mods.map(m=><option key={m.id} value={m.id}>{m.id}. {m.name} — {m.category}</option>)}</select><button onClick={()=>setEdit({status:'open',priority:'normal'})}>+ Novi zapis</button></div><div className="card"><h3>{mod?.name}</h3><p>{mod?.description}</p><div className="kpis small"><K label="Kategorija" val={mod?.category}/><K label="Zapisa" val={rows.length}/><K label="Otvoreno" val={rows.filter(r=>r.status!=='closed').length}/><K label="Vrijednost" val={money(rows.reduce((s,r)=>s+Number(r.amount||0),0))}/></div></div><div className="card tableWrap"><table><thead><tr><th>Naslov</th><th>Status</th><th>Prioritet</th><th>Iznos</th><th>Rok</th><th>Akcije</th></tr></thead><tbody>{rows.map(r=><tr key={r.id}><td>{r.title}</td><td>{r.status}</td><td>{r.priority}</td><td>{money(r.amount)}</td><td>{date(r.due_date)}</td><td><button onClick={()=>setEdit({...r,...(r.data||{})})}>Uredi</button><button className="danger" onClick={()=>del(r.id)}>Briši</button></td></tr>)}</tbody></table></div>{edit&&<FeatureForm row={edit} onClose={()=>setEdit(null)} onSave={save}/>}</> }
function FeatureForm({row,onClose,onSave}:any){ const [f,setF]=useState<Row>(row); return <div className="modal"><form className="modalCard" onSubmit={e=>{e.preventDefault();onSave(f)}}><div className="modalHead"><h2>Poslovna funkcija</h2><button type="button" onClick={onClose}>✕</button></div><div className="formGrid"><label>Naslov<input required value={f.title||''} onChange={e=>setF({...f,title:e.target.value})}/></label><label>Status<select value={f.status||'open'} onChange={e=>setF({...f,status:e.target.value})}>{['open','in_progress','waiting','closed'].map(x=><option key={x}>{x}</option>)}</select></label><label>Prioritet<select value={f.priority||'normal'} onChange={e=>setF({...f,priority:e.target.value})}>{['low','normal','high','critical'].map(x=><option key={x}>{x}</option>)}</select></label><label>Iznos<input type="number" value={f.amount||0} onChange={e=>setF({...f,amount:e.target.value})}/></label><label>Rok<input type="date" value={f.due_date||''} onChange={e=>setF({...f,due_date:e.target.value})}/></label><label>Rizik<select value={f.rizik||'srednji'} onChange={e=>setF({...f,rizik:e.target.value})}>{['nizak','srednji','visok'].map(x=><option key={x}>{x}</option>)}</select></label><label>Opis<textarea required value={f.opis||''} onChange={e=>setF({...f,opis:e.target.value})}/></label><label>Odgovorna osoba<input value={f.odgovorna_osoba||''} onChange={e=>setF({...f,odgovorna_osoba:e.target.value})}/></label><label>Napomena<textarea value={f.napomena||''} onChange={e=>setF({...f,napomena:e.target.value})}/></label></div><div className="modalActions"><button type="button" onClick={onClose}>Odustani</button><button>Spremi</button></div></form></div> }

createRoot(document.getElementById('root')!).render(<App/>);
